import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./Register.css";

function Register() {
  const navigate = useNavigate();
  const [user, setUser] = useState(null);

  // ================= TOKEN HANDLE =================
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const token = params.get("token") || localStorage.getItem("auth_token");

    if (token) {
      try {
        // JWT decode
        const base64Payload = token.split(".")[1];
        const payload = JSON.parse(window.atob(base64Payload));

        // Save to localStorage
        localStorage.setItem("auth_token", token);
        if (payload._id) localStorage.setItem("userId", payload._id);
        if (payload.mbtiType) localStorage.setItem("userType", payload.mbtiType);

        // Update state
        setUser(payload);

        // Redirect if pending result
        const pending = localStorage.getItem("pendingResult");
        if (pending) {
          navigate(`/result?type=${pending}`, { replace: true });
        } else if (!params.get("token")) {
          navigate("/", { replace: true });
        }

      } catch (err) {
        console.log("Token decode error", err);
      } finally {
        window.history.replaceState({}, document.title, "/register");
        localStorage.removeItem("google_login_started"); // Clear login guard
      }
    }
  }, [navigate]);

  // ================= GOOGLE LOGIN =================
  const handleGoogleLogin = () => {
    if (localStorage.getItem("google_login_started")) return; // prevent double login
    localStorage.setItem("google_login_started", "true");
    window.location.href = "http://localhost:5000/auth/google";
  };

  // ================= USER PHOTO =================
  const getUserPhoto = () => {
    if (!user) return "/images/default.png";
    let photo = user.photo || "";
    if (photo.startsWith("http:")) photo = photo.replace("http:", "https:");
    return photo || "/images/default.png";
  };

  const userPhoto = getUserPhoto();

  return (
    <div className="register-page">
      <div className="register-card">
        <h2 className="register-title">ავტორიზაცია</h2>

        <p className="register-description">
          გაიარე ავტორიზაცია Google ანგარიშით და შეინახე შენი MBTI შედეგები
        </p>

        {/* მხოლოდ როცა user არ არის ლოგინში */}
        {!user && (
          <button className="google-signin" onClick={handleGoogleLogin}>
            <img
              src="https://developers.google.com/identity/images/g-logo.png"
              alt="Google"
            />
            Continue with Google
          </button>
        )}

        {/* როცა user უკვე არსებობს */}
        {user && (
          <div className="register-user-preview">
            <img
              src={userPhoto}
              alt={user.email}
              className="register-user-photo"
              referrerPolicy="no-referrer"
              onError={(e) => (e.target.src = "/images/default.png")}
            />
            <p>მოგესალმებით, {user.name}</p>
          </div>
        )}
      </div>
    </div>
  );
}

export default Register;
